import os
from cryptography.hazmat.primitives import padding
from cryptography.hazmat.primitives.ciphers import Cipher, algorithms, modes
from cryptography.hazmat.backends import default_backend
import base64

# Load encryption key from application config
encryption_key = os.environ['ENCRYPTION_KEY']

def encrypt_credit_card(card_number):
    # Generate a random 128-bit initialization vector (IV)
    iv = os.urandom(16)

    # Create a new AES cipher object with the encryption key and IV
    cipher = Cipher(algorithms.AES(encryption_key), modes.CBC(iv), backend=default_backend())
    encryptor = cipher.encryptor()

    # Pad the card number to ensure it's a multiple of the block size (128 bits)
    padder = padding.PKCS7(128).padder()
    padded_card_number = padder.update(card_number) + padder.finalize()

    # Encrypt the padded card number
    encrypted_card_number = encryptor.update(padded_card_number) + encryptor.finalize()

    # Return the IV and encrypted card number as a single byte string
    return iv + encrypted_card_number

def decrypt_credit_card(encrypted_card_number):
    # Extract the IV from the start of the byte string
    iv = encrypted_card_number[:16]

    # Create a new AES cipher object with the encryption key and IV
    cipher = Cipher(algorithms.AES(encryption_key), modes.CBC(iv), backend=default_backend())
    decryptor = cipher.decryptor()

    # Decrypt the card number
    decrypted_padded_card_number = decryptor.update(encrypted_card_number[16:]) + decryptor.finalize()

    # Unpad the decrypted card number
    unpadder = padding.PKCS7(128).unpadder()
    card_number = unpadder.update(decrypted_padded_card_number) + unpadder.finalize()

    return card_number

# Example usage:
card_number = '1234-5678-9012-3456'
encrypted_card_number = encrypt_credit_card(card_number)
print('Encrypted card number:', base64.b64encode(encrypted_card_number).decode())

decrypted_card_number = decrypt_credit_card(base64.b64decode(encrypted_card_number))
print('Decrypted card number:', decrypted_card_number)